+  if (!providers) {
+    return;
+  }
+
+  const existing = providers.get(providerId);
+  if (!existing || existing.extensionId !== extensionId) {
+    return;
+  }
+
+  providers.delete(providerId);
+  if (providers.size === 0) {
+    workspaceProvidersByProject.delete(resolvedProjectCwd);
